import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";


function ProductDetail()
{
    const navigate = useNavigate();
    const { category, slug } = useParams(); // Get 'category' and 'slug' from the URL
    const [loading, setLoading] = useState(true);
    const [product, setProduct] = useState(null); // Use a single object for the product
    const [productCategory, setProductCategory] = useState(null); // To avoid naming conflict

    useEffect(() =>
    {
        let isMounted = true;

        // Use the destructured category and slug from useParams
        axios.get(`/api/viewProductDetail/${category}/${slug}`).then(res =>
        {
            if (isMounted)
            {
                console.log(res.data);
                if (res.data.status === 200)
                {
                    setProduct(res.data.product); // API should return a single product
                    setProductCategory(res.data.category);
                    setLoading(false);
                }
                else if (res.data.status === 404)
                {
                    // Use navigate for redirection
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching products:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category, slug, navigate]); // Dependency array includes category and slug

    if (loading)
    {
        return <h4>Loading Products Details...</h4>;
    }

    if (!product)
    {
        return <h4>Product Not Found.</h4>;
    }

    var avail_stock = "";
    if (product.qty > 0)
    {
        avail_stock = (
            <div>
                <label className="btn-sm btn-success px-4 mt-2">In Stock</label>

                <div className="row">
                    <div className="col-md-3 mt-3">
                        <div className="input-group">
                            <button type="button" className="input-group-text">-</button>
                            <input type="text" className="form-control text-center" value="1" readOnly />
                            <button type="button" className="input-group-text">+</button>
                        </div>
                    </div>
                    <div className="col-md-9 mt-3">
                        <button type="button" className="btn btn-primary w-100">Add to Cart</button>
                    </div>
                </div>
            </div>
        );
    }
    else
    {
        avail_stock = (
            <div>
                <label className="btn-sm btn-danger px-4 mt-2">Out of Stock</label>
            </div>
        );
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Collections / {productCategory?.name} / {product.name}</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">

                        {/* Product Details */}
                        <div className="col-md-4 border-end">
                            <img src={`http://localhost:8000/${product.image}`} alt={product.name} className="w-100" />
                        </div>

                        {/* Product Information */}
                        <div className="col-md-8">
                            <h4>
                                {product.name}
                                <span className="float-end badge btn-sm btn-danger badge-pil">
                                    {product.brand}
                                </span>
                            </h4>
                            <p>{product.description}</p>
                            <h4 className="mb-1">
                                KSH: {product.selling_price}
                                <s className="ms-2"> KSH: {product.mrp} </s>
                            </h4>
                            <div>
                                {avail_stock}
                            </div>

                            <button className="btn btn-danger mt-3"> Add to Wishlist </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}
export default ProductDetail;
